script:
const $r = root_element;
const $ = (sel) => $r.querySelector(sel);
const escape = (s) => frappe.utils.escape_html(s == null ? "" : String(s));

function bindEvents() {
  const zone = $("#ai-drop-zone");
  const input = $("#ai-file-input");
  zone.addEventListener("dragover", (e) => { e.preventDefault(); zone.classList.add("drag-over"); });
  zone.addEventListener("dragleave", () => zone.classList.remove("drag-over"));
  zone.addEventListener("drop", (e) => {
    e.preventDefault();
    zone.classList.remove("drag-over");
    if (e.dataTransfer.files.length) uploadFiles(e.dataTransfer.files);
  });
  zone.addEventListener("click", () => input.click());
  input.addEventListener("change", () => { if (input.files.length) uploadFiles(input.files); });
}

function uploadFiles(files) {
  const prog = $("#ai-progress");
  prog.style.display = "block";
  prog.className = "ai-progress";
  prog.textContent = `Uploading ${files.length} file(s)…`;

  Promise.all(Array.from(files).map(uploadOne))
    .then((results) => {
      const flat = results.flat();
      prog.className = "ai-progress success";
      prog.innerHTML = `✓ ${flat.length} import job(s) queued — <strong>${flat.map(escape).join(", ")}</strong>`;
      refreshJobs();
      $("#ai-file-input").value = "";
    })
    .catch((err) => {
      prog.className = "ai-progress error";
      prog.textContent = "Upload failed: " + (err.message || err);
    });
}

function uploadOne(file) {
  const fd = new FormData();
  fd.append("file", file);
  return fetch("/api/method/erpnext_ai_importer.api.upload.upload_invoice", {
    method: "POST",
    headers: { "X-Frappe-CSRF-Token": frappe.csrf_token },
    body: fd,
  }).then(r => r.json()).then(data => {
    if (data.exc) throw new Error(data._server_messages || data.exc);
    return data.message || [];
  });
}

function refreshJobs() {
  return frappe.call({
    method: "frappe.client.get_list",
    args: {
      doctype: "AI Document Import",
      fields: ["name","company","party","extracted_supplier_name","total","status","purchase_invoice","source_file","creation","supplier_match_score"],
      order_by: "creation desc",
      limit: 50,
    },
  }).then(r => renderJobs(r.message || []));
}

function renderJobs(rows) {
  const count = $("#ai-job-count");
  const list = $("#ai-job-list");
  if (!rows.length) {
    count.textContent = "";
    list.innerHTML = `<div class="ai-empty">No imports yet — drop a file above to get started.</div>`;
    return;
  }
  count.textContent = `${rows.length} records`;
  const tbody = rows.map(r => `<tr>
    <td>${fileIcon(r.source_file)} ${escape(fileName(r))}</td>
    <td>${escape(r.company || "—")}</td>
    <td>${partyCell(r)}</td>
    <td>${r.total ? frappe.format(r.total, {fieldtype:"Currency"}) : "—"}</td>
    <td>${statusBadge(r.status)}</td>
    <td>${actionCell(r)}</td>
  </tr>`).join("");
  list.innerHTML = `<table class="ai-table">
    <thead><tr><th>File</th><th>Company</th><th>Supplier</th><th>Total</th><th>Status</th><th></th></tr></thead>
    <tbody>${tbody}</tbody>
  </table>`;
}

function fileName(r) { return r.source_file ? r.source_file.split("/").pop() : r.name; }
function fileIcon(sf) {
  if (!sf) return "📄";
  const ext = sf.split(".").pop().toLowerCase();
  if (ext === "zip") return "📦";
  if (["xlsx","xls","csv"].includes(ext)) return "📊";
  return "📄";
}
function partyCell(row) {
  if (!row.party) {
    if (row.extracted_supplier_name) return `<span style="color:#C7201A">⚠ No match for "${escape(row.extracted_supplier_name)}"</span>`;
    return "—";
  }
  const score = row.supplier_match_score || 0;
  const color = score >= 85 ? "#0D7C3D" : score >= 60 ? "#A85A00" : "#C7201A";
  return `<span style="color:${color}">${escape(row.party)}</span> <span style="font-size:10px;color:#9BB5CC;margin-left:4px">${score}%</span>`;
}
function statusBadge(status) {
  const map = {
    "Draft":               { bg:"#F4F7FB", color:"#5A7A9A" },
    "Extracting":          { bg:"#E8F2FF", color:"#0958B3" },
    "Pending Validation":  { bg:"#FFF3E0", color:"#A85A00" },
    "Potential Duplicate": { bg:"#FDECEA", color:"#C7201A" },
    "Submitted":           { bg:"#EAF7EE", color:"#0D7C3D" },
    "Failed":              { bg:"#FDECEA", color:"#C7201A" },
  };
  const s = map[status] || { bg:"#F4F7FB", color:"#5A7A9A" };
  return `<span class="ai-badge" style="background:${s.bg};color:${s.color}">${escape(status||"")}</span>`;
}
function actionCell(row) {
  if (row.status === "Submitted" && row.purchase_invoice) {
    const url = frappe.utils.get_form_link("Purchase Invoice", row.purchase_invoice);
    return `<a class="ai-link" href="${url}">${escape(row.purchase_invoice)}</a>`;
  }
  const url = "/app/ai-invoice-validate/" + encodeURIComponent(row.name);
  if (row.status === "Pending Validation" || row.status === "Potential Duplicate" || row.status === "Failed")
    return `<a class="ai-link" href="${url}">${row.status === "Failed" ? "View →" : "Validate →"}</a>`;
  if (row.status === "Extracting")
    return `<span style="color:#9BB5CC;font-size:11px">Processing…</span>`;
  return `<a class="ai-link" href="${url}">View →</a>`;
}

bindEvents();
refreshJobs();
setInterval(refreshJobs, 10000);

style:
.ai-root {
  --blue:#0B70E1; --blue-dk:#0958B3; --blue-lt:#E8F2FF;
  --navy:#0B1D3A; --border:#D8E4F0; --bg:#F4F7FB; --surface:#FFFFFF;
  --text:#0B1D3A; --text-sub:#5A7A9A; --text-muted:#9BB5CC;
  --ok:#0D7C3D; --ok-bg:#EAF7EE; --ok-bd:#A7D7BA;
  --err:#C7201A; --err-bg:#FDECEA;
  --warn:#A85A00; --warn-bg:#FFF3E0;
  --r-sm:6px; --r-md:10px;
  --sh-sm:0 1px 4px rgba(11,29,58,.07);
  max-width:960px; margin:0 auto; padding:0 2px;
  font-family:'Inter','Segoe UI',-apple-system,sans-serif;
}
.ai-drop-zone {
  border:2px dashed var(--border); border-radius:var(--r-md);
  padding:48px 32px; text-align:center; background:var(--bg);
  cursor:pointer; transition:background 0.15s,border-color 0.15s; margin-bottom:14px;
}
.ai-drop-zone:hover, .ai-drop-zone.drag-over { background:var(--blue-lt); border-color:var(--blue); }
.ai-dz-icon { font-size:2.2rem; color:var(--text-muted); margin-bottom:6px; }
.ai-dz-title { font-size:14px; font-weight:600; color:var(--text); }
.ai-dz-hint { font-size:12px; color:var(--text-muted); margin-top:4px; }
#ai-file-input { display:none; }
.ai-progress {
  margin-bottom:12px; padding:10px 14px; border-radius:var(--r-sm);
  font-size:12px; background:var(--blue-lt); border:1px solid var(--border); color:var(--blue-dk);
}
.ai-progress.success { background:var(--ok-bg); border-color:var(--ok-bd); color:var(--ok); }
.ai-progress.error   { background:var(--err-bg); border-color:#F5AAAA; color:var(--err); }
.ai-card {
  background:var(--surface); border:1px solid var(--border);
  border-radius:var(--r-md); overflow:hidden; box-shadow:var(--sh-sm);
}
.ai-card-head {
  display:flex; justify-content:space-between; align-items:center;
  padding:12px 16px; border-bottom:1px solid var(--border); background:var(--bg);
}
.ai-card-title { font-size:13px; font-weight:600; color:var(--text); }
.ai-card-sub   { font-size:11px; color:var(--text-muted); }
.ai-empty { padding:32px; text-align:center; color:var(--text-muted); font-size:13px; }
.ai-table { width:100%; border-collapse:collapse; font-size:12px; }
.ai-table th {
  color:var(--text-muted); font-size:10px; text-transform:uppercase;
  letter-spacing:0.04em; font-weight:700; padding:8px 12px;
  border-bottom:1px solid var(--border); text-align:left; background:var(--bg);
}
.ai-table td {
  padding:8px 12px; border-bottom:1px solid var(--bg);
  color:var(--text); vertical-align:middle;
}
.ai-table tbody tr:last-child td { border-bottom:none; }
.ai-table tbody tr:hover { background:var(--blue-lt); }
.ai-badge { display:inline-block; padding:2px 8px; border-radius:var(--r-sm); font-size:10px; font-weight:600; white-space:nowrap; }
.ai-link { color:var(--blue); text-decoration:none; font-size:11px; }
.ai-link:hover { text-decoration:underline; }
